"use client";

/**
 * Opener for the `shareModal` overlay.
 *
 * - `useOpenShareModal()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<ShareModalController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "shareModal" as const;

export interface OpenShareModalOptions {
  /** Optional stable instance id. Omit to spawn a fresh instance. */
  instanceId?: string;
  /** TODO: tighten to `ResourceType` once that type is imported. */
  resourceType: unknown;
  resourceId: string;
  resourceName: string;
  isOwner: boolean;
}

export interface ShareModalHandle {
  instanceId: string;
  close: () => void;
}

export function useOpenShareModal() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenShareModalOptions): ShareModalHandle => {
      const instanceId = opts.instanceId ?? `shareModal-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          instanceId,
          data: {
            resourceType: opts.resourceType,
            resourceId: opts.resourceId,
            resourceName: opts.resourceName,
            isOwner: opts.isOwner,
          },
        }),
      );
      return {
        instanceId,
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID, instanceId })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function ShareModalController(props: OpenShareModalOptions): null {
  const open = useOpenShareModal();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.resourceType, props.resourceId, props.resourceName, props.isOwner]);
  return null;
}
